package models


type TrackPlayState struct {
	TrackId      int    `json:"track_id"`
	UserId       int    `json:"user_id"`
	PlayCount    int    `json:"play_count"`
	LastPlayedAt string `json:"last_played_at"`
}

type FavoriteTrack struct {
	TrackId      int    `json:"track_id"`
	UserId       int    `json:"user_id"`
	CreatedAt    string `json:"created_at"`
}

type LastPlayedTrack struct {
	UserId    int    `json:"user_id"`
	TrackId   int    `json:"track_id"`
	PlayedAt  string `json:"played_at"`
}

package db

import (
	"aaxion/internal/models"
	"fmt"
	"log"
)

// RecordPlay updates the play count and last played time for a user and track.
func RecordPlay(trackId int, userId int, lastPlayedAt string) {
	query := `
		INSERT INTO music_stats (track_id, user_id, play_count, last_played_at) 
		VALUES (?, ?, 1, ?) 
		ON CONFLICT(user_id, track_id) DO UPDATE SET 
			play_count = play_count + 1,
			last_played_at = ?
	`
	_, err := GetDB().Exec(query, trackId, userId, lastPlayedAt, lastPlayedAt)
	if err != nil {
		log.Println("Got err updating play state", err)
	}
}

// SetFavorite toggles or explicitly sets the favorite status.
func SetFavorite(trackId int, userId int, isFavorite bool) {
	query := `
		INSERT INTO music_stats (track_id, user_id, is_favorite) 
		VALUES (?, ?, ?) 
		ON CONFLICT(user_id, track_id) DO UPDATE SET 
			is_favorite = ?
	`
	_, err := GetDB().Exec(query, trackId, userId, isFavorite, isFavorite)
	if err != nil {
		log.Println("Got err updating favorite state", err)
	}
}

// GetUserTrackStats returns the detailed stats for a specific user and track.
func GetUserTrackStats(trackId int, userId int) (state models.MusicStats, err error) {
	query := "SELECT track_id, user_id, is_favorite, play_count, last_played_at FROM music_stats WHERE user_id = ? AND track_id = ?"

	row := GetDB().QueryRow(query, userId, trackId)

	err = row.Scan(&state.TrackId, &state.UserId, &state.IsFavorite, &state.PlayCount, &state.LastPlayedAt)
	// Return a default zero-state if record doesn't exist yet
	if err != nil {
		state = models.MusicStats{TrackId: trackId, UserId: userId, IsFavorite: false, PlayCount: 0}
		err = nil
	}
	return
}

// GetUserLastPlayedTrack returns the single most recently played track for a user across all tracks.
func GetUserLastPlayedTrack(userId int) (state models.MusicStats, err error) {
	query := "SELECT track_id, user_id, is_favorite, play_count, last_played_at FROM music_stats WHERE user_id = ? AND last_played_at IS NOT NULL ORDER BY last_played_at DESC LIMIT 1"

	row := GetDB().QueryRow(query, userId)

	err = row.Scan(&state.TrackId, &state.UserId, &state.IsFavorite, &state.PlayCount, &state.LastPlayedAt)
	if err != nil {
		err = fmt.Errorf("no last played track found for user")
	}
	return
}

func DeleteState(trackId int, userId int){
	query := "DELETE FROM music_stats WHERE track_id = ? AND user_id = ?"
	_, err := GetDB().Exec(query, trackId, userId)
	if err != nil {
		log.Println("Got delete err", err)
	}
}

package db

import (
	"aaxion/internal/models"
	"database/sql"
	"log"
)

// RecordPlay updates the play count and last played time for a user and track,
// and optionally sets the user's global last played track.
func RecordPlay(trackId int, userId int, playedAt string) {
	// Update play_states
	playQuery := `
		INSERT INTO play_states (user_id, track_id, play_count, last_played_at) 
		VALUES (?, ?, 1, ?) 
		ON CONFLICT(user_id, track_id) DO UPDATE SET 
			play_count = play_count + 1,
			last_played_at = ?
	`
	_, err := GetDB().Exec(playQuery, userId, trackId, playedAt, playedAt)
	if err != nil {
		log.Println("Got err updating play state", err)
	}

	// Update last_played_tracks (global)
	lastPlayedQuery := `
		INSERT INTO last_played_tracks (user_id, track_id, played_at) 
		VALUES (?, ?, ?) 
		ON CONFLICT(user_id) DO UPDATE SET 
			track_id = ?,
			played_at = ?
	`
	_, err = GetDB().Exec(lastPlayedQuery, userId, trackId, playedAt, trackId, playedAt)
	if err != nil {
		log.Println("Got err updating last played track", err)
	}
}

// SetFavorite toggles or explicitly sets the favorite status.
func SetFavorite(trackId int, userId int, isFavorite bool) {
	if isFavorite {
		query := "INSERT OR IGNORE INTO favorite_tracks (user_id, track_id) VALUES (?, ?)"
		_, err := GetDB().Exec(query, userId, trackId)
		if err != nil {
			log.Println("Got err adding favorite", err)
		}
	} else {
		query := "DELETE FROM favorite_tracks WHERE user_id = ? AND track_id = ?"
		_, err := GetDB().Exec(query, userId, trackId)
		if err != nil {
			log.Println("Got err removing favorite", err)
		}
	}
}

// GetPlayState returns the play state for a specific user and track.
func GetPlayState(trackId int, userId int) (state models.TrackPlayState, err error) {
	query := "SELECT user_id, track_id, play_count, last_played_at FROM play_states WHERE user_id = ? AND track_id = ?"

	row := GetDB().QueryRow(query, userId, trackId)

	err = row.Scan(&state.UserId, &state.TrackId, &state.PlayCount, &state.LastPlayedAt)
	if err == sql.ErrNoRows {
		state = models.TrackPlayState{UserId: userId, TrackId: trackId, PlayCount: 0}
		err = nil
	}
	return
}

// CheckFavorite checks if a track is favorited by the user.
func CheckFavorite(trackId int, userId int) bool {
	var id int
	query := "SELECT id FROM favorite_tracks WHERE user_id = ? AND track_id = ?"
	err := GetDB().QueryRow(query, userId, trackId).Scan(&id)
	return err == nil
}

// GetUserLastPlayedTrack returns the single most recently played track for a user.
func GetUserLastPlayedTrack(userId int) (state models.LastPlayedTrack, err error) {
	query := "SELECT user_id, track_id, played_at FROM last_played_tracks WHERE user_id = ?"

	row := GetDB().QueryRow(query, userId)

	err = row.Scan(&state.UserId, &state.TrackId, &state.PlayedAt)
	return
}

func DeletePlayState(trackId int, userId int){
	query := "DELETE FROM play_states WHERE track_id = ? AND user_id = ?"
	_, err := GetDB().Exec(query, trackId, userId)
	if err != nil {
		log.Println("Got delete err", err)
	}
}
